    "s_final = (yf.Ticker(\"HDFCBANK.NS\").history(period=\"1d\", interval=\"1m\")[\"High\"].iloc[-2] +\n",
    "           yf.Ticker(\"HDFCBANK.NS\").history(period=\"1d\", interval=\"1m\")[\"Low\"].iloc[-2]) / 2\n",
    "\n",
    "if portfolio_live.inventory > 0:\n",
    "    for _ in range(portfolio_live.inventory):\n",
    "        portfolio_live.sell(s_final)\n",
    "    print(f\"Flattened LONG: sold {abs(portfolio_live.inventory)} shares @ ₹{s_final:.2f}\")\n",
    "\n",
    "elif portfolio_live.inventory < 0:\n",
    "    for _ in range(abs(portfolio_live.inventory)):\n",
    "        portfolio_live.buy(s_final)\n",
    "    print(f\"Flattened SHORT: bought {abs(portfolio_live.inventory)} shares @ ₹{s_final:.2f}\")\n",
    "\n",
    "else:\n",
    "    print(\"Inventory already flat.\")\n",
    "\n",
    "pnl_final = portfolio_live.wealth(s_final) - 100000\n",
    "print(f\"Final P&L after close-out: ₹{pnl_final:+.2f}\")\n",
    "print(f\"Inventory: {portfolio_live.inventory}\")"
